1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	interface Item {
11	  type: string;
12	}
13	
14	interface Step {
15	  op: string;
16	  items?: Item[];
17	}
18	
19	interface Scenario {
20	  customer: { yearsWithMHPCO: number };
21	  steps: Step[];
22	}
23	
24	const sumBasePremiums = (items: Item[]): number =>
25	  items.reduce((sum, it) => sum + BASE_PREMIUM[it.type], 0);
26	
27	const applyFirstInsuranceSurcharge = (base: number): number =>
28	  Math.ceil((base * (100 + FIRST_INSURANCE_PERCENT)) / 100);
29	
30	const quotePremium = (items: Item[]): number =>
31	  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
32	
33	export const runScenario = (input: unknown): { results: unknown[] } => {
34	  const scenario = input as Scenario;
35	  const results = scenario.steps.map((step) => ({
36	    premium: quotePremium(step.items ?? []),
37	  }));
38	  return { results };
39	};
